3288	\begin{lemma}
3289	[Naturality of the sheaf-level pullback--tensor comparison $\delta_{\mathrm{sheaf}}$ (D1$'$)]
3290	  \label{lem:pullback_tensor_map_natural}
3291	  \lean{AlgebraicGeometry.Scheme.Modules.pullbackTensorMap_natural}
3292	  \uses{lem:pullback_tensor_map, lem:presheaf_pullback_oplaxmonoidal}
3293	  Let \(f : Y \to X\) be a morphism of schemes. The sheaf-level comparison map
3294	  \(\delta_{\mathrm{sheaf}} = \mathtt{pullbackTensorMap}\) of
3295	  \cref{lem:pullback_tensor_map} is \emph{natural} in both module arguments: for
3296	  morphisms \(a : M \to M'\) and \(b : N \to N'\) in \(\Scheme.\mathtt{Modules}\,X\)
3297	  the square
3298	  \[
3299	    \begin{array}{ccc}
3300	      f^*(M \otimes_X N)
3301	        & \xrightarrow{\;\delta_{\mathrm{sheaf}}\;}
3302	        & f^*M \otimes_Y f^*N \\[2pt]
3303	      \big\downarrow{\scriptstyle f^*(a \otimes b)}
3304	        & & \big\downarrow{\scriptstyle f^*a \,\otimes\, f^*b} \\[4pt]
3305	      f^*(M' \otimes_X N')
3306	        & \xrightarrow{\;\delta_{\mathrm{sheaf}}\;}
3307	        & f^*M' \otimes_Y f^*N'
3308	    \end{array}
3309	  \]
3310	  commutes.
3311	\end{lemma}
3312	
3313	\begin{proof}
3314	  \uses{lem:pullback_tensor_map, lem:presheaf_pullback_oplaxmonoidal}
3315	  The map \(\delta_{\mathrm{sheaf}}\) is built (\cref{lem:pullback_tensor_map}) by
3316	  transporting the abstract oplax comparison \(\delta\) of the presheaf pullback
3317	  (\cref{lem:presheaf_pullback_oplaxmonoidal}) through the sheafification
3318	  reconciliations. Each ingredient is natural: the abstract oplax \(\delta\) is natural
3319	  in both arguments --- this is Mathlib's
3320	  \(\mathtt{Functor.OplaxMonoidal.}\delta\mathtt{\_natural}\), valid for any oplax
3321	  monoidal functor --- and the sheafification, the \(\mathtt{sheafificationCompPullback}\)
3322	  comparison, and the unit/tensor reconciliation \(\mathtt{sheafifyTensorUnitIso}\) are
3323	  natural transformations. The asserted square is the pasting of these naturality squares,
3324	  so it commutes; naturality in the two arguments is checked separately and then combined,
3325	  the tensor of the two component morphisms factoring as \(f^*a \otimes f^*b\) by
3326	  bifunctoriality of \(\otimes_Y\).
3327	\end{proof}
